import React, { useState, useEffect } from 'react';
import './DoctorSignup.css'; // Import the CSS file below

const DoctorSignup = () => {
    const [formData, setFormData] = useState({
        fullName: '',
        email: '',
        mobile: '',
        dob: '',
        gender: '',
        password: '',
        confirmPassword: '',
        terms: false
    });

    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);
    const [isLoading, setIsLoading] = useState(false);

    // Dynamic date constraints (Must be 21+ years old)
    const today = new Date();
    const maxDate = new Date(today.getFullYear() - 21, today.getMonth(), today.getDate()).toISOString().split('T')[0];
    const minDate = new Date(today.getFullYear() - 80, today.getMonth(), today.getDate()).toISOString().split('T')[0];

    const handleInputChange = (e) => {
        const { id, value, type, checked } = e.target;
        setFormData(prev => ({
            ...prev,
            [id]: type === 'checkbox' ? checked : value
        }));
    };

    const handleSubmit = (e) => {
        e.preventDefault();

        // Validation logic
        if (formData.password !== formData.confirmPassword) {
            alert("Passwords do not match!");
            return;
        }

        setIsLoading(true);

        // Simulate API call
        setTimeout(() => {
            console.log('Saving Data:', formData);
            localStorage.setItem('doctorPersonalData', JSON.stringify({
                ...formData,
                password: btoa(formData.password) // Basic obfuscation
            }));
            setIsLoading(false);
            alert('Step 1 Complete! Moving to Professional Info...');
            // In a real app, use: navigate('/step2')
        }, 1500);
    };

    return (
        <div className="registration-page">
            {/* Header */}
            <header className="header">
                <div className="container navbar">
                    <div className="logo"><img src="logo.png" alt="Logo" /></div>
                    <ul className="nav-menu">
                        <li><a href="/" className="nav-link active">Home</a></li>
                        <li><a href="#" className="nav-link">Features</a></li>
                        <li><a href="#" className="nav-link">Doctors</a></li>
                    </ul>
                    <div className="nav-buttons">
                        <button className="btn btn-login">Log In</button>
                        <button className="btn btn-primary-nav">Sign Up Free</button>
                    </div>
                </div>
            </header>

            <main className="main-content">
                <div className="container">
                    <div className="registration-wrapper">
                        {/* Steps Indicator */}
                        <div className="steps">
                            <div className="step active">
                                <div className="step-number">1</div>
                                <div className="step-label">Personal Info</div>
                            </div>
                            <div className="step">
                                <div className="step-number">2</div>
                                <div className="step-label">Professional Info</div>
                            </div>
                            <div className="step">
                                <div className="step-number">3</div>
                                <div className="step-label">Verification</div>
                            </div>
                        </div>

                        {/* Form Container */}
                        <div className="form-container">
                            <div className="form-header">
                                <h1>Doctor Registration</h1>
                                <p>Step 1: Fill in your personal information</p>
                            </div>

                            <form onSubmit={handleSubmit}>
                                <div className="form-group">
                                    <label className="form-label">Full Name</label>
                                    <input 
                                        type="text" id="fullName" className="form-control" 
                                        placeholder="Dr. First Last Name" required 
                                        value={formData.fullName} onChange={handleInputChange}
                                    />
                                    <span className="form-helper">As per your medical license</span>
                                </div>

                                <div className="form-group">
                                    <label className="form-label">Professional Email</label>
                                    <input 
                                        type="email" id="email" className="form-control" 
                                        placeholder="doctor@hospital.com" required 
                                        value={formData.email} onChange={handleInputChange}
                                    />
                                </div>

                                <div className="form-row">
                                    <div className="form-group">
                                        <label className="form-label">Mobile Number</label>
                                        <input 
                                            type="tel" id="mobile" className="form-control" 
                                            placeholder="07XXXXXXXX" required 
                                            value={formData.mobile} onChange={handleInputChange}
                                        />
                                    </div>
                                    <div className="form-group">
                                        <label className="form-label">Date of Birth</label>
                                        <input 
                                            type="date" id="dob" className="form-control" 
                                            min={minDate} max={maxDate} required 
                                            value={formData.dob} onChange={handleInputChange}
                                        />
                                    </div>
                                </div>

                                <div className="form-group">
                                    <label className="form-label">Gender</label>
                                    <select id="gender" className="form-control" required value={formData.gender} onChange={handleInputChange}>
                                        <option value="" disabled>Select Gender</option>
                                        <option value="male">Male</option>
                                        <option value="female">Female</option>
                                        <option value="other">Other</option>
                                    </select>
                                </div>

                                <div className="form-group">
                                    <label className="form-label">Password</label>
                                    <div className="password-wrapper">
                                        <input 
                                            type={showPassword ? "text" : "password"} 
                                            id="password" className="form-control" required 
                                            value={formData.password} onChange={handleInputChange}
                                        />
                                        <button type="button" className="password-toggle" onClick={() => setShowPassword(!showPassword)}>
                                            <i className={showPassword ? "fas fa-eye-slash" : "fas fa-eye"}></i>
                                        </button>
                                    </div>
                                </div>

                                <div className="form-group">
                                    <label className="form-label">Confirm Password</label>
                                    <div className="password-wrapper">
                                        <input 
                                            type={showConfirmPassword ? "text" : "password"} 
                                            id="confirmPassword" className="form-control" required 
                                            value={formData.confirmPassword} onChange={handleInputChange}
                                        />
                                        <button type="button" className="password-toggle" onClick={() => setShowConfirmPassword(!showConfirmPassword)}>
                                            <i className={showConfirmPassword ? "fas fa-eye-slash" : "fas fa-eye"}></i>
                                        </button>
                                    </div>
                                </div>

                                <div className="terms">
                                    <input type="checkbox" id="terms" checked={formData.terms} onChange={handleInputChange} required />
                                    <label htmlFor="terms">I agree to the <a href="#">Terms of Service</a></label>
                                </div>

                                <button type="submit" className="btn btn-primary" disabled={isLoading}>
                                    {isLoading ? "Processing..." : "Continue to Step 2"}
                                </button>
                            </form>
                        </div>
                    </div>
                </div>
            </main>

            {/* Footer */}
            <footer className="footer">
                <div className="container">
                    <div className="footer-bottom">
                        <p>&copy; 2026 Channel4Me. All rights reserved.</p>
                    </div>
                </div>
            </footer>
        </div>
    );
};

export default DoctorSignup;
